const text = $('Analyze search terms & suggest keyword exclusions/inclusions').first().json.text;

const tableMatch = text.match(/\| search_term \|.*?\n([\s\S]*?)(?=## PART 3|## RECOMMENDED GLOBAL EXCLUSIONS|$)/);
if (!tableMatch) throw new Error("Table not found in AI output");

const rows = tableMatch[1]
  .split('\n')
  .filter(line => line.startsWith('|') && !line.match(/^\|[-| ]+\|$/))
  .map(line => {
    const cols = line.split('|').slice(1, -1).map(c => c.trim());
    return {
      search_term:            cols[0],
      status:                 cols[1],
      campaign:               cols[2],
      ad_group:               cols[3],
      matched_keyword:        cols[4],
      match_type:             cols[5],
      impressions:            cols[6],
      clicks:                 cols[7],
      ctr:                    cols[8],
      cost:                   cols[9],
      avg_cpc:                cols[10],
      avg_cpm:                cols[11],
      conversion_rate:        cols[12],
      cost_per_conversion:    cols[13],
      intent_signal:          cols[14],
      relevancy:              cols[15],
      relevancy_reasoning:    cols[16],
      exclusion_suggestion:   cols[17],
      exclusion_level:        cols[18],
      priority_for_exclusion: cols[19],
      inclusion_suggestion:   cols[20],
      inclusion_type:         cols[21],
      inclusion_level:        cols[22],
    };
  })
  .filter(row => row.search_term && row.search_term !== '---');

return rows.map(json => ({ json }));

