// Get results array from first input item
const rawData = $input.first().json;

// Support both formats: direct array or object with results property
const resultsArray = Array.isArray(rawData)
  ? rawData[0].results
  : rawData.results;

// Formatting helper functions
function formatPercent(value) {
  const parsed = parseFloat(value);
  // Return 0% if value is null, undefined, or NaN
  if (isNaN(parsed)) return '0%';
  const pct = parsed * 100;
  return (pct % 1 === 0 ? pct.toFixed(0) : pct.toFixed(2)) + '%';
}

function formatDollar(micros) {
  const dollars = parseFloat(micros) / 1_000_000;
  return '$' + (dollars % 1 === 0 ? dollars.toFixed(0) : dollars.toFixed(2));
}

function formatDollarDirect(value) {
  const parsed = parseFloat(value);
  // Return $0 if value is null, undefined, or NaN (e.g. avg_cpc when clicks = 0)
  if (isNaN(parsed)) return '$0';
  const dollars = parsed / 1_000_000;
  return '$' + (dollars % 1 === 0 ? dollars.toFixed(0) : dollars.toFixed(2));
}

function formatConversions(value) {
  return Math.round(parseFloat(value)).toString();
}

// Map and clean each search term entry
const cleanedResults = resultsArray.map(item => {
  const m = item.metrics;
  const stv = item.searchTermView;
  const seg = item.segments?.keyword?.info || {};

  // cost_per_conversion can be undefined/null/0
  let costPerConv = 'N/A';
  if (m.costPerConversion !== undefined && m.costPerConversion !== null) {
    const val = parseFloat(m.costPerConversion);
    costPerConv = val > 0 ? formatDollarDirect(m.costPerConversion) : '$0';
  }

  // Get campaign type from campaign.advertisingChannelType
  const campaignType = item.campaign?.advertisingChannelType ?? 'UNKNOWN';

  return {
    search_term: stv.searchTerm,
    status: stv.status,
    campaign: item.campaign.name,
    campaign_type: campaignType,
    ad_group: item.adGroup.name,
    matched_keyword: seg.text || 'N/A',
    match_type: seg.matchType || 'N/A',
    impressions: parseInt(m.impressions),
    clicks: parseInt(m.clicks),
    ctr: formatPercent(m.ctr),
    cost: formatDollar(m.costMicros),
    avg_cpc: formatDollarDirect(m.averageCpc),
    avg_cpm: formatDollarDirect(m.averageCpm),
    conversions: formatConversions(m.conversions),
    conversion_rate: formatPercent(m.conversionsFromInteractionsRate),
    cost_per_conversion: costPerConv
  };
})
// Filter: keep only rows with impressions >= 2 OR clicks >= 1
.filter(row => row.impressions >= 5 || row.clicks >= 1);

// Sort by impressions descending (highest first)
cleanedResults.sort((a, b) => b.impressions - a.impressions);

// Return as a single item with the cleaned search terms array
return [{
  json: {
    total_search_terms: cleanedResults.length,
    search_terms: cleanedResults
  }
}];

