const text = $('Analyze search terms & suggest keyword exclusions/inclusions').first().json.text;

const part3Match = text.match(/##\s+(?:PART\s+3\s*[—\-]+\s*)?RECOMMENDED GLOBAL EXCLUSIONS[\s\S]*/i);
if (!part3Match) throw new Error("RECOMMENDED GLOBAL EXCLUSIONS section not found — check AI output format");

const part3 = part3Match[0];
const rows = [];
let currentGroup = '';

for (const line of part3.split('\n')) {

  const groupMatch = line.match(/###\s+(Group \d+[^$]*)/);
  if (groupMatch) {
    currentGroup = groupMatch[1].trim();
    continue;
  }

  if (line.startsWith('|') && !line.match(/^\|[-| ]+\|$/) && !line.includes('Negative Keyword')) {
    const cols = line.split('|').slice(1, -1).map(c => c.trim());
    if (cols[0] && cols[0] !== '') {
      rows.push({
        json: {
          group:            currentGroup,
          negative_keyword: cols[0].replace(/^"|"$/g, ''),
          match_type:       cols[1],
          rationale:        cols[2],
        }
      });
    }
  }
}

return rows;

const text = $('Analyze search terms & suggest keyword exclusions/inclusions').first().json.text;

const inferenceMatch = text.match(/## PART 1 — INFERENCE SUMMARY([\s\S]*?)(?=## PART 2 — SEARCH TERMS ANALYSIS TABLE)/);

if (!inferenceMatch || !inferenceMatch[1].trim()) {
  return [{ json: { inference_summary: null } }];
}

const inferenceText = inferenceMatch[1]
  .trim()
  .replace(/\n{3,}/g, '\n\n');

return [{
  json: {
    inference_summary: inferenceText
  }
}];
